static void update_datetime_view()
{
	DateTimeView_main->setDate(g_month,g_day,g_weekday);
	DateTimeView_main->setTime(g_hour,g_min);
	DateTimeView_main->updateTime();

}
static void update_battery_view(){
#ifdef SUPPORT_BATTERY
#ifdef DRV_CORE
	int bat_soc;
         int charging_status;
	goldie_read(battery_fd, (uint8_t*)&bat_soc, sizeof(bat_soc));
	goldie_ioctl(battery_fd,BAT_IOCTL_GET_CHGSTATUS,&charging_status);
#else
	int bat_soc = battery_drv->read_power();
	int charging_status = battery_drv->is_charging();
#endif
	BatteryView_main->setBatteryLevel(bat_soc);
	if(charging_status){
		BatteryView_main->setCharging(true);
	}else{
		BatteryView_main->setCharging(false);
	}
#else
	BatteryView_main->setBatteryLevel(50);
#endif
}

// Battery power update callback from event service
static void update_bat_msg(BroadcastMessage* msg) {
    goldie_mutex_lock(&ui_mutex);
    if (msg && BatteryView_main) {
       update_battery_view();
    }
    goldie_mutex_unlock(&ui_mutex);	
}

// Timer thread function - updates time every second
static void time_update(BroadcastMessage* msg) {    
    (void)msg;
    goldie_mutex_lock(&ui_mutex);
	if((msg->msg)&&(msg->msg_len == sizeof(struct tm)))
	{	
		struct tm* current_time = (struct tm*)(msg->msg);
		printf("time_update: %04d-%02d-%02d %02d:%02d:%02d (Week%d)\r\n",
			   current_time->tm_year+1900, current_time->tm_mon+1, current_time->tm_mday,
			   current_time->tm_hour, current_time->tm_min, current_time->tm_sec,
			   current_time->tm_wday);
	
		   g_month =current_time->tm_mon+1;
		   g_day =current_time->tm_mday;
		   g_weekday = current_time->tm_wday;
		   g_hour = current_time->tm_hour+8;
		   if(g_hour>=24){
			g_hour = g_hour -24;
		   }
		   g_min = current_time->tm_min;
	}

	if ((app_status ==1) && (DateTimeView_main)) {
		update_datetime_view();
        }

#ifdef CYCLE_BATTERY_TEST
    // 测试：每秒循环电量变化（0→100→0）
    if (evt_service) {
        static int cycle_battery_level = 0;       // 当前电量，初始为0
        static int cycle_direction = 1;           // 变化方向：1表示增加，-1表示减少
        static int cycle_charging = 0;            // 充电状态，0表示未充电
        
        // 每秒变化10%
        cycle_battery_level += (10 * cycle_direction);
        
        // 边界检查与方向反转
        if (cycle_battery_level >= 100) {
            cycle_battery_level = 100;            // 确保不超过100
            cycle_direction = -1;                 // 到达100后开始减少
            cycle_charging = 0;                   // 电量满时停止充电（如果需要）
        } else if (cycle_battery_level <= 0) {
            cycle_battery_level = 0;              // 确保不低于0
            cycle_direction = 1;                  // 到达0后开始增加
            cycle_charging = 1;                   // 电量为0时开始充电（如果需要）
        }
        BatteryView_main->setBatteryLevel(cycle_battery_level);
        // 更新充电状态（可选，根据您的需求）
        if (BatteryView_main) {
            BatteryView_main->setCharging(cycle_charging);
        }
        
        // 调试信息
        printf("[CYCLE_TEST] Battery: %d%%, Charging: %d, Direction: %s\n", 
               cycle_battery_level, cycle_charging, 
               cycle_direction > 0 ? "UP" : "DOWN");
    }
#endif


#ifdef RANDOM_TEST_BATTERY_SVC
        // Test: Broadcast random battery status every second
        if (evt_service) {
            test_battery_counter++;
            // Generate random battery level (0-100) using counter for pseudo-randomness
            // Cycle through different battery levels for testing
            int random_battery = (test_battery_counter * 17 + 23) % 101;  // Pseudo-random 0-100
            
            // Also randomly toggle charging state
            bool random_charging = (test_battery_counter % 3) == 0;  // Charging 1/3 of the time
            
            // Create and send battery power broadcast message
            BroadcastMessage bat_msg = {0};
            bat_msg.id = EVENT_BROADCAST_POWER;
            bat_msg.ext[0] = random_battery;
            bat_msg.msg_len = sizeof(int);
            
            evt_service->send_broadcast(&bat_msg);
            
            // Update charging state directly (since there's no charging broadcast event yet)
            if (BatteryView_main) {
                BatteryView_main->setCharging(random_charging);
                // Refresh battery view area
                if (Window_main && Window_main->isVisible() && FrameView_main && FrameView_status) {
                    int bat_x = FrameView_main->getX() + FrameView_status->getX() + BatteryView_main->getX();
                    int bat_y = FrameView_main->getY() + FrameView_status->getY() + BatteryView_main->getY();
                    int bat_w = BatteryView_main->getWidth();
                    int bat_h = BatteryView_main->getHeight();
                    Window_main->flush(bat_x, bat_y, bat_w, bat_h);
                }
            }
        }
#endif
	if(wifi_service)
	{
		if(wifi_service->svr_sta_isConnected())
		{
			WifiView_main->setSignalLevel(WIFI_SIGNAL_STRONG);
		}else{
            WifiView_main->setSignalLevel(WIFI_SIGNAL_NONE);
        }
	}
    #ifdef SUPPORT_SLE
    if(sle_service)
    {
        if(sle_service->svr_is_enabled())
		{
			NearLinkView_main->setStatus(NEARLINK_ENABLED);
		}else{
            NearLinkView_main->setStatus(NEARLINK_DISABLED);
        }
    }else {
        // 如果支持SLE但服务获取失败，也视为禁用
        NearLinkView_main->setStatus(NEARLINK_DISABLED);
    }
    #else
        // 如果系统不支持SLE，则直接将其状态设置为禁用
        NearLinkView_main->setStatus(NEARLINK_DISABLED);
    #endif
    goldie_mutex_unlock(&ui_mutex);
	    return;
}

