// Show app icons in ScrollView (horizontal scroll)
// Uses ICON_WIDTH/ICON_HEIGHT from goldie_display.h (56x56)
static void show_apps(App_t** app_list, int list_count) {
    // Clear existing app buttons and labels
    for (auto& btn : app_buttons) {
        ScrollView_main->removeChild(btn);
    }
    for (auto& lbl : app_labels) {
        ScrollView_main->removeChild(lbl);
    }
    app_buttons.clear();
    app_labels.clear();
    
    int visible_app_count = 0;
    
    // Count visible apps (apps with icons)
    for (int i = 0; i < list_count; i++) {
        if (app_list[i]->icon) {
            visible_app_count++;
        }
    }
    
    // Calculate total content width (same layout as luncher)
    // Layout: start_x + n * (ICON_WIDTH + spacing)
    int total_width = LAUNCHER_START_X + visible_app_count * (ICON_WIDTH + LAUNCHER_ICON_SPACING);
    if (total_width <= APP_WINDOW_WIDTH) {
        total_width = APP_WINDOW_WIDTH;  // Minimum width
    } else {
        ScrollView_main->setScrollEnabled(true);
    }
    printf("total_width %d \r\n",total_width);
    ScrollView_main->setContentWidth(total_width);
    
    // Add app icons and labels
    int x_pos = LAUNCHER_START_X;  // Starting X position (same as luncher: 16)
    for (int i = 0; i < list_count; i++) {
        if (!app_list[i]->icon) {
            continue;
        }
        
        //不显示无屏设备
        if (app_list[i]->app_name && strcmp(app_list[i]->app_name, "test") == 0) {
            continue;
        }

        // Create button for app icon (56x56)
        auto button = std::make_shared<ButtonView>(ICON_WIDTH, ICON_HEIGHT);
        button->setBoundaryBuffer(gImage_round_icon_boundary);
        button->setImageBuffer(app_list[i]->icon);
        button->setVisible(true);
        
        // Calculate vertical centering: ScrollView height is 120, icon+label total is 76
        int total_content_height = ICON_HEIGHT + LAUNCHER_LABEL_HEIGHT;  // 56 + 20 = 76
        int scroll_view_height = 120;
        int y_icon = (scroll_view_height - total_content_height) / 2;  // Center vertically
        
        ScrollView_main->addView(button, x_pos, y_icon);
        
        // Create label for app name below icon (same as luncher: ICON_WIDTH x 20)
        auto label = std::make_shared<LabelView>(ICON_WIDTH, LAUNCHER_LABEL_HEIGHT);
        label->setTextColor(0);
        label->setTransparent(true);
        label->setText(app_list[i]->app_name);
        label->setVisible(true);
        
        // Label position: below icon
        int y_label = y_icon + ICON_HEIGHT;
        ScrollView_main->addView(label, x_pos, y_label);
        
        // Set click handler to run the app
        App_t* current_app = app_list[i];
        button->setOnClick([current_app](void*) {
            goldie_run_app(current_app);
        });
        
        app_buttons.push_back(button);
        app_labels.push_back(label);
        
        // Spacing same as luncher: ICON_WIDTH + 24
        x_pos += ICON_WIDTH + LAUNCHER_ICON_SPACING;
    }
    
    // Refresh display
    Window_main->flush(0, 0, APP_WINDOW_WIDTH, APP_WINDOW_HEIGHT);
}

static void goldie_app_run(void)
{
    goldie_mutex_init(&ui_mutex);
    goldie_mutex_lock(&ui_mutex);
    wifi_service = (WifiService*)wait_service(WIFI_SERVICE_INDEX);
    #ifdef SUPPORT_SLE
    sle_service = (SleSdpService*)wait_service(SLE_SDP_SERVICE_INDEX);
    #endif
#ifdef SUPPORT_BATTERY
#ifdef DRV_CORE
          battery_fd = goldie_open(BAT_DRV_NAME, O_RDONLY);
#else
	battery_drv = (BatDrv*)wait_drv(BATTERY_DRV_INDEX);
#endif
#endif
    // Get app list
    app_list = get_app_list(&app_count);
    
    // Initialize UI
    main_ui_init();
	
	update_datetime_view();
	update_battery_view();
    // Show apps in ScrollView
    show_apps(app_list, app_count);
    
    // Register event service for battery power updates
    evt_service = (EventService*)wait_service(EVENT_SERVICE_INDEX);
    if (evt_service) {
        evt_service->register_broadcast_recv(EVENT_BROADCAST_POWER, update_bat_msg);
        evt_service->register_broadcast_recv(EVENT_BROADCAST_TIMERUPDATE, time_update);
    }
    app_status = 1;
    goldie_mutex_unlock(&ui_mutex);		
}

static void goldie_app_suspend(void)
{
    goldie_mutex_lock(&ui_mutex);	
    window_suspend();
    app_status = 0;
    goldie_mutex_unlock(&ui_mutex);		
}

static void goldie_app_resume(void)
{
    goldie_mutex_lock(&ui_mutex);
    window_resume();
	update_datetime_view();
	update_battery_view();
    app_status = 1;
    goldie_mutex_unlock(&ui_mutex);			
}

static void goldie_app_exit(void)
{
    goldie_mutex_lock(&ui_mutex);
    window_exit();
    app_status = 0;
#ifdef SUPPORT_BATTERY	
#ifdef DRV_CORE
		goldie_close(battery_fd);
#endif
#endif
    goldie_mutex_unlock(&ui_mutex);	
}

static void goldie_keyboard_event(int pressure, int key);

static App_t launcher = {
    "launcher",       // app_name char*
    goldie_app_run,       // h_app_run
    nullptr, //goldie_app_exit,      // h_app_exit
    goldie_app_suspend,   // h_app_suspend
    goldie_app_resume,    // h_app_resume
    goldie_touch_event,   // h_touch_event
    goldie_keyboard_event,// h_keyboard_event
    nullptr, //(uint16_t*)gImage_default_icon,             
};

static void goldie_keyboard_event(int pressure, int key)
{
    if((key == SYSTEM_KEY_VALUE_BACK) && (pressure == 1))
    {
        goldie_exit_app(&launcher);
    }else if ((key == SYSTEM_KEY_VALUE_WAKEUP) && (pressure == 1)) //右键进入对讲机APP
    {
        for (int i = 0; i < app_count; i++) 
        {
            if (app_list[i] && app_list[i]->app_name) 
            {
                if (strcmp(app_list[i]->app_name, "对讲机") == 0) 
                {
                    goldie_run_app(app_list[i]);
                    return;
                }
            }
        }
        printf("[Launcher] 未在应用列表中找到“对讲机”应用。\n");
    }
}

static void launcher_entry(void)
{
    install_app(&launcher);
}

GOLDIE_INIT_CALL_(launcher_entry);
